insert into public.movies (id, title, original_title, release_year, runtime_minutes, overview, poster_url, backdrop_url, trailer_url, language_code, country_code, tmdb_id)
values
  ('c55374ec-c344-2fa1-fe10-b28662d5da39', 'The Godfather', 'The Godfather', 1972, 175, 'Spanning the years 1945 to 1955, a chronicle of the fictional Italian-American Corleone crime family. When organized crime family patriarch, Vito Corleone barely survives an attempt on his life, his youngest son, Michael steps in to take care of the would-be killers, launching a campaign of bloody revenge.', 'https://image.tmdb.org/t/p/w500/3bhkrj58Vtu7enYsRolD1fZdja1.jpg', 'https://image.tmdb.org/t/p/w1280/tSPT36ZKlP2WVHJLM4cQPLSzv3b.jpg', null, 'en', 'US', 238),
  ('e24dd8f0-d2b3-a6f5-0f1e-da13118917f5', 'The Godfather Part II', 'The Godfather Part II', 1974, 202, 'In the continuing saga of the Corleone crime family, a young Vito Corleone grows up in Sicily and in 1910s New York. In the 1950s, Michael Corleone attempts to expand the family business into Las Vegas, Hollywood and Cuba.', 'https://image.tmdb.org/t/p/w500/hek3koDUyRQk7FIhPXsa6mT2Zc3.jpg', 'https://image.tmdb.org/t/p/w1280/kGzFbGhp99zva6oZODW5atUtnqi.jpg', null, 'en', 'US', 240),
  ('ad837d86-d0a3-aee5-e648-5e82849efbec', 'Pulp Fiction', 'Pulp Fiction', 1994, 154, 'A burger-loving hit man, his philosophical partner, a drug-addled gangster''s moll and a washed-up boxer converge in this sprawling, comedic crime caper. Their adventures unfurl in three stories that ingeniously trip back and forth in time.', 'https://image.tmdb.org/t/p/w500/vQWk5YBFWF4bZaofAbv0tShwBvQ.jpg', 'https://image.tmdb.org/t/p/w1280/suaEOtk1N1sgg2MTM7oZd2cfVp3.jpg', null, 'en', 'US', 680),
  ('55d0c28f-a3c3-4459-53d9-f7d38f7ebfcd', 'The Shawshank Redemption', 'The Shawshank Redemption', 1994, 142, 'Imprisoned in the 1940s for the double murder of his wife and her lover, upstanding banker Andy Dufresne begins a new life at the Shawshank prison, where he puts his accounting skills to work for an amoral warden. During his long stretch in prison, Dufresne comes to be admired by the other inmates -- including an older prisoner named Red -- for his integrity and unquenchable sense of hope.', 'https://image.tmdb.org/t/p/w500/9cqNxx0GxF0bflZmeSMuL5tnGzr.jpg', 'https://image.tmdb.org/t/p/w1280/zfbjgQE1uSd9wiPTX4VzsLi0rGG.jpg', null, 'en', 'US', 278),
  ('be1c212c-2497-23bf-92dd-98267e43e6f6', 'Schindler''s List', 'Schindler''s List', 1993, 195, 'The true story of how businessman Oskar Schindler saved over a thousand Jewish lives from the Nazis while they worked as slaves in his factory during World War II.', 'https://image.tmdb.org/t/p/w500/sF1U4EUQS8YHUYjNl3pMGNIQyr0.jpg', 'https://image.tmdb.org/t/p/w1280/zb6fM1CX41D9rF9hdgclu0peUmy.jpg', null, 'en', 'US', 424),
  ('d65a9cff-cb90-8397-491e-4996c90507bc', '12 Angry Men', '12 Angry Men', 1957, 97, 'The defense and the prosecution have rested and the jury is filing into the jury room to decide if a young Spanish-American is guilty or innocent of murdering his father. What begins as an open and shut case soon becomes a mini-drama of each of the jurors'' prejudices and preconceptions about the trial, the accused, and each other.', 'https://image.tmdb.org/t/p/w500/zhG3vKWyDRaZYoaww1UVAi29T9h.jpg', 'https://image.tmdb.org/t/p/w1280/w4bTBXcqXc2TUyS5Fc4h67uWbPn.jpg', null, 'en', 'US', 389),
  ('94c3ed6f-7751-2a9a-f292-ff92e976e98a', 'Psycho', 'Psycho', 1960, 109, 'When larcenous real estate clerk Marion Crane goes on the lam with a wad of cash and hopes of starting a new life, she ends up at the notorious Bates Motel, where manager Norman Bates cares for his housebound mother.', 'https://image.tmdb.org/t/p/w500/yz4QVqPx3h1hD1DfqqQkCq3rmxW.jpg', 'https://image.tmdb.org/t/p/w1280/mufF1aYvwdpKerhq5R1YrVcbJLY.jpg', null, 'en', 'US', 539),
  ('58a0e20c-1c0c-1cee-6be3-14807599b9af', 'Casablanca', 'Casablanca', 1943, 102, 'In Casablanca, Morocco in December 1941, a cynical American expatriate meets a former lover, with unforeseen complications.', 'https://image.tmdb.org/t/p/w500/lGCEKlJo2CnWydQj7aamY7s1S7Q.jpg', 'https://image.tmdb.org/t/p/w1280/87wqeMeUeMRLjsE1IWNKJcPlpuC.jpg', null, 'en', 'US', 289),
  ('34581f8a-172b-c736-52d9-163951495144', 'Citizen Kane', 'Citizen Kane', 1941, 119, 'Newspaper magnate Charles Foster Kane is taken from his mother as a boy and made the ward of a rich industrialist. As a result, every well-meaning, tyrannical or self-destructive move he makes for the rest of his life appears in some way to be a reaction to that deeply wounding event.', 'https://image.tmdb.org/t/p/w500/sav0jxhqiH0bPr2vZFU0Kjt2nZL.jpg', 'https://image.tmdb.org/t/p/w1280/9Y85oA1y6toL2OACXdaC6iTl7eQ.jpg', null, 'en', 'US', 15),
  ('b30d561b-051b-4d22-2a86-1fa29e734931', 'Vertigo', 'Vertigo', 1958, 128, 'A retired San Francisco detective suffering from acrophobia investigates the strange activities of an old friend''s wife, all the while becoming dangerously obsessed with her.', 'https://image.tmdb.org/t/p/w500/15uOEfqBNTVtDUT7hGBVCka0rZz.jpg', 'https://image.tmdb.org/t/p/w1280/rtVwkTqllcmyY4TVOycgVBHppWf.jpg', null, 'en', 'US', 426),
  ('eeb78b42-a6e1-638f-7187-7470f8472d10', 'Rear Window', 'Rear Window', 1954, 112, 'A wheelchair-bound photographer spies on his neighbors from his apartment window and becomes convinced one of them has committed murder.', 'https://image.tmdb.org/t/p/w500/ILVF0eJxHMddjxeQhswFtpMtqx.jpg', 'https://image.tmdb.org/t/p/w1280/zGs5tZOlvc9cprdcU6kDOVNpujf.jpg', null, 'en', 'US', 567),
  ('1c3d269a-6374-3f53-202d-28e3f22aa535', 'North by Northwest', 'North by Northwest', 1959, 137, 'Advertising man Roger Thornhill is mistaken for a spy, triggering a deadly cross-country chase.', 'https://image.tmdb.org/t/p/w500/kNOFPQrel9YFCVzI0DF8FnCEpCw.jpg', 'https://image.tmdb.org/t/p/w1280/OR8oloCZ3klJtB7Y0i8pSqWw5a.jpg', null, 'en', 'US', 213),
  ('5c27d432-b825-f54b-2f95-8fd45faca8cf', 'Taxi Driver', 'Taxi Driver', 1976, 114, 'Suffering from insomnia, disturbed loner Travis Bickle takes a job as a New York City cabbie, haunting the streets nightly, growing increasingly detached from reality as he dreams of cleaning up the filthy city.', 'https://image.tmdb.org/t/p/w500/ekstpH614fwDX8DUln1a2Opz0N8.jpg', 'https://image.tmdb.org/t/p/w1280/5MVSXJieOhbyZudCnV1H4YJpfPV.jpg', null, 'en', 'US', 103),
  ('280e6b3e-382f-5429-d8fa-ec016b8c7950', 'Apocalypse Now', 'Apocalypse Now', 1979, 147, 'At the height of the Vietnam war, Captain Benjamin Willard is sent on a dangerous mission that, officially, "does not exist, nor will it ever exist." His goal is to locate - and eliminate - a mysterious Green Beret Colonel named Walter Kurtz, who has been leading his personal army on illegal guerrilla missions into enemy territory.', 'https://image.tmdb.org/t/p/w500/gQB8Y5RCMkv2zwzFHbUJX3kAhvA.jpg', 'https://image.tmdb.org/t/p/w1280/49fzLedFVKgGgFChLMuulDJBY1c.jpg', null, 'en', 'US', 28),
  ('18aaf747-e6d6-b352-cae0-bee2e3c10dd0', 'Raging Bull', 'Raging Bull', 1980, 129, 'The life of boxer Jake LaMotta, whose violence and temper that led him to the top in the ring destroyed his life outside of it.', 'https://image.tmdb.org/t/p/w500/1WV7WlTS8LI1L5NkCgjWT9GSW3O.jpg', 'https://image.tmdb.org/t/p/w1280/tvNuhRlpRozDgsX1zR9gQ2aHv1X.jpg', null, 'en', 'US', 1578),
  ('6eaf0f68-6860-3d56-965e-450b56103059', 'One Flew Over the Cuckoo''s Nest', 'One Flew Over the Cuckoo''s Nest', 1975, 133, 'A petty criminal fakes insanity to serve his sentence in a mental ward rather than prison. He soon finds himself as a leader to the other patients—and an enemy to the cruel, domineering nurse who runs the ward.', 'https://image.tmdb.org/t/p/w500/kjWsMh72V6d8KRLV4EOoSJLT1H7.jpg', 'https://image.tmdb.org/t/p/w1280/6Oa3zTiluBz2W8D2ou1MY16dUiF.jpg', null, 'en', 'US', 510),
  ('df7d9757-333b-ae65-e999-1323c219a772', 'GoodFellas', 'GoodFellas', 1990, 145, 'The true story of Henry Hill, a half-Irish, half-Sicilian Brooklyn kid who is adopted by neighbourhood gangsters at an early age and climbs the ranks of a Mafia family under the guidance of Jimmy Conway.', 'https://image.tmdb.org/t/p/w500/9OkCLM73MIU2CrKZbqiT8Ln1wY2.jpg', 'https://image.tmdb.org/t/p/w1280/gILte6Zd7m1YneIr6MVhh30S9pr.jpg', null, 'en', 'US', 769),
  ('19a2b1d6-c748-84c2-b334-fe80be3b9347', 'The Silence of the Lambs', 'The Silence of the Lambs', 1991, 119, 'Clarice Starling is a top student at the FBI''s training academy.  Jack Crawford wants Clarice to interview Dr. Hannibal Lecter, a brilliant psychiatrist who is also a violent psychopath, serving life behind bars for various acts of murder and cannibalism.  Crawford believes that Lecter may have insight into a case and that Starling, as an attractive young woman, may be just the bait to draw him out.', 'https://image.tmdb.org/t/p/w500/uS9m8OBk1A8eM9I042bx8XXpqAq.jpg', 'https://image.tmdb.org/t/p/w1280/aYcnDyLMnpKce1FOYUpZrXtgUye.jpg', null, 'en', 'US', 274),
  ('07cc962a-d4a4-f8a3-3d0f-6dc72c181d7f', 'Se7en', 'Se7en', 1995, 127, 'Two homicide detectives are on a desperate hunt for a serial killer whose crimes are based on the "seven deadly sins" in this dark and haunting film that takes viewers from the tortured remains of one victim to the next. The seasoned Det. Somerset researches each sin in an effort to get inside the killer''s mind, while his novice partner, Mills, scoffs at his efforts to unravel the case.', 'https://image.tmdb.org/t/p/w500/191nKfP0ehp3uIvWqgPbFmI4lv9.jpg', 'https://image.tmdb.org/t/p/w1280/i5H7zusQGsysGQ8i6P361Vnr0n2.jpg', null, 'en', 'US', 807),
  ('cc13d13c-f222-c612-c134-0e0f1935e968', 'The Usual Suspects', 'The Usual Suspects', 1995, 106, 'Held in an L.A. interrogation room, Verbal Kint attempts to convince the feds that a mythic crime lord, Keyser Soze, not only exists, but was also responsible for drawing him and his four partners into a multi-million dollar heist that ended with an explosion in San Pedro harbor – leaving few survivors. Verbal lures his interrogators with an incredible story of the crime lord''s almost supernatural prowess.', 'https://image.tmdb.org/t/p/w500/99X2SgyFunJFXGAYnDv3sb9pnUD.jpg', 'https://image.tmdb.org/t/p/w1280/hy0Hx9fMPk2fmw26Li60z1S2giU.jpg', null, 'en', 'US', 629),
  ('aa50a235-bcb7-062c-9524-3f83cda3ba45', 'Léon: The Professional', 'Léon', 1994, 111, 'Léon, the top hit man in New York, has earned a rep as an effective "cleaner". But when his next-door neighbors are wiped out by a loose-cannon DEA agent, he becomes the unwilling custodian of 12-year-old Mathilda. Before long, Mathilda''s thoughts turn to revenge, and she considers following in Léon''s footsteps.', 'https://image.tmdb.org/t/p/w500/bxB2q91nKYp8JNzqE7t7TWBVupB.jpg', 'https://image.tmdb.org/t/p/w1280/jRJrQ72VLyEnVsvwfep8Xjlvu8c.jpg', null, 'fr', 'FR', 101),
  ('2e8def09-c7c7-bc8a-685c-7dc25f862d31', 'American History X', 'American History X', 1998, 119, 'Derek Vineyard is paroled after serving 3 years in prison for killing two African-American men. Through his brother, Danny Vineyard''s narration, we learn that before going to prison, Derek was a skinhead and the leader of a violent white supremacist gang that committed acts of racial crime throughout L.A. and his actions greatly influenced Danny. Reformed and fresh out of prison, Derek severs contact with the gang and becomes determined to keep Danny from going down the same violent path as he did.', 'https://image.tmdb.org/t/p/w500/x2drgoXYZ8484lqyDj7L1CEVR4T.jpg', 'https://image.tmdb.org/t/p/w1280/6qHI1IYj7QlLSCwHRzkL62X175s.jpg', null, 'en', 'US', 73),
  ('ef5bbf4c-b97e-3171-53fa-3e38c6294868', 'American Beauty', 'American Beauty', 1999, 122, 'Lester Burnham, a depressed suburban father in a mid-life crisis, decides to turn his hectic life around after developing an infatuation with his daughter''s attractive friend.', 'https://image.tmdb.org/t/p/w500/wby9315QzVKdW9BonAefg8jGTTb.jpg', 'https://image.tmdb.org/t/p/w1280/2ndw55F40IkALzWyjCCza3M6nqM.jpg', null, 'en', 'US', 14),
  ('94ebbfaf-d21e-1647-8f60-955f838ff434', 'Memento', 'Memento', 2000, 113, 'Leonard Shelby is tracking down the man who raped and murdered his wife. The difficulty of locating his wife''s killer, however, is compounded by the fact that he suffers from a rare, untreatable form of short-term memory loss. Although he can recall details of life before his accident, Leonard cannot remember what happened fifteen minutes ago, where he''s going, or why.', 'https://image.tmdb.org/t/p/w500/fKTPH2WvH8nHTXeBYBVhawtRqtR.jpg', 'https://image.tmdb.org/t/p/w1280/7Wev9JMo6R5XAfz2KDvXb7oPMmy.jpg', null, 'en', 'US', 77),
  ('f844f28e-e1b8-6056-d70c-8fa08308fd1e', 'Eternal Sunshine of the Spotless Mind', 'Eternal Sunshine of the Spotless Mind', 2004, 108, 'Joel Barish, heartbroken that his girlfriend underwent a procedure to erase him from her memory, decides to do the same. However, as he watches his memories of her fade away, he realises that he still loves her, and may be too late to correct his mistake.', 'https://image.tmdb.org/t/p/w500/5MwkWH9tYHv3mV9OdYTMR5qreIz.jpg', 'https://image.tmdb.org/t/p/w1280/W1ffLQGHoxfAOq0ZYdPtJlvAdb.jpg', null, 'en', 'US', 38),
  ('b42995e4-1fd0-92e2-f410-f30b8d1f58e4', 'Requiem for a Dream', 'Requiem for a Dream', 2000, 102, 'The drug-induced utopias of four Coney Island residents are shattered when their addictions run deep.', 'https://image.tmdb.org/t/p/w500/nOd6vjEmzCT0k4VYqsA2hwyi87C.jpg', 'https://image.tmdb.org/t/p/w1280/7tZt3PA948fvSTFx0699YF44Tdt.jpg', null, 'en', 'US', 641),
  ('165876b1-29e9-8040-6f91-4341a4d0b28d', 'Kill Bill: Vol. 1', 'Kill Bill: Vol. 1', 2003, 111, 'An assassin is shot by her ruthless employer, Bill, and other members of their assassination circle – but she lives to plot her vengeance.', 'https://image.tmdb.org/t/p/w500/v7TaX8kXMXs5yFFGR41guUDNcnB.jpg', 'https://image.tmdb.org/t/p/w1280/iffzIhuLAO38Po6sh1s6ZEVwlNL.jpg', null, 'en', 'US', 24),
  ('ee884d78-094e-f2bd-895f-b5d77326978f', 'The Matrix', 'The Matrix', 1999, 136, 'Set in the 22nd century, The Matrix tells the story of a computer hacker who joins a group of underground insurgents fighting the vast and powerful computers who now rule the earth.', 'https://image.tmdb.org/t/p/w500/aOIuZAjPaRIE6CMzbazvcHuHXDc.jpg', 'https://image.tmdb.org/t/p/w1280/tlm8UkiQsitc8rSuIAscQDCnP8d.jpg', null, 'en', 'US', 603),
  ('8083e6fc-c7bd-04d9-2bf4-372cd36028d1', 'Blade Runner', 'Blade Runner', 1982, 118, 'In the smog-choked dystopian Los Angeles of 2019, blade runner Rick Deckard is called out of retirement to terminate a quartet of replicants who have escaped to Earth seeking their creator for a way to extend their short life spans.', 'https://image.tmdb.org/t/p/w500/63N9uy8nd9j7Eog2axPQ8lbr3Wj.jpg', 'https://image.tmdb.org/t/p/w1280/qr7dUqleMRd0VgollazbmyP9XjI.jpg', null, 'en', 'US', 78),
  ('4fc90b44-58e7-a7f2-85ff-07e9e43224d5', '2001: A Space Odyssey', '2001: A Space Odyssey', 1968, 149, 'Humanity finds a mysterious object buried beneath the lunar surface and sets off to find its origins with the help of HAL 9000, the world''s most advanced super computer.', 'https://image.tmdb.org/t/p/w500/ve72VxNqjGM69Uky4WTo2bK6rfq.jpg', 'https://image.tmdb.org/t/p/w1280/30XRuUQGk5P9XB6mlfEF1eoWFgq.jpg', null, 'en', 'US', 62),
  ('aa91feba-03bd-5828-de69-9b18dd520f69', 'A Clockwork Orange', 'A Clockwork Orange', 1971, 137, 'In a near-future Britain, young Alexander DeLarge and his pals get their kicks beating and raping anyone they please. When not destroying the lives of others, Alex swoons to the music of Beethoven. The state, eager to crack down on juvenile crime, gives an incarcerated Alex the option to undergo an invasive procedure that''ll rob him of all personal agency. In a time when conscience is a commodity, can Alex change his tune?', 'https://image.tmdb.org/t/p/w500/4sHeTAp65WrSSuc05nRBKddhBxO.jpg', 'https://image.tmdb.org/t/p/w1280/nLFxvLokHe3bQmrmAfljIfax2jQ.jpg', null, 'en', 'GB', 185),
  ('fa3825d2-9a49-7a54-50cd-1a89b3d202e6', 'Alien', 'Alien', 1979, 117, 'During its return to the earth, commercial spaceship Nostromo intercepts a distress signal from a distant planet. When a three-member team of the crew discovers a chamber containing thousands of eggs on the planet, a creature inside one of the eggs attacks an explorer. The entire crew is unaware of the impending nightmare set to descend upon them when the alien parasite planted inside its unfortunate host is birthed.', 'https://image.tmdb.org/t/p/w500/vfrQk5IPloGg1v9Rzbh2Eg3VGyM.jpg', 'https://image.tmdb.org/t/p/w1280/cEobq5QrnOJjO6giDs8q4RxmMKh.jpg', null, 'en', 'US', 348),
  ('044983cd-818b-8548-ebfa-305e6e575e61', 'Aliens', 'Aliens', 1986, 137, 'Ripley, the sole survivor of the Nostromo''s deadly encounter with the monstrous Alien, returns to Earth after drifting through space in hypersleep for 57 years. Although her story is initially met with skepticism, she agrees to accompany a team of Colonial Marines back to LV-426.', 'https://image.tmdb.org/t/p/w500/r1x5JGpyqZU8PYhbs4UcrO1Xb6x.jpg', 'https://image.tmdb.org/t/p/w1280/4kix6fAblJIH6eMs0Ku2loyZJXK.jpg', null, 'en', 'US', 679),
  ('27a38fe9-023a-7007-1abc-a69396b52edd', 'Jaws', 'Jaws', 1975, 124, 'When the seaside community of Amity finds itself under attack by a dangerous great white shark, the town''s chief of police, a young marine biologist, and a grizzled shark hunter embark on a desperate quest to kill the beast before it strikes again.', 'https://image.tmdb.org/t/p/w500/tjbLSFwi0I3phZwh8zoHWNfbsEp.jpg', 'https://image.tmdb.org/t/p/w1280/i1yf91svRHX45l9BXL8rVFzLoPH.jpg', null, 'en', 'US', 578),
  ('5967f976-57c2-fde1-c8d2-633d8143a5fc', 'The Shining', 'The Shining', 1980, 144, 'Jack Torrance accepts a caretaker job at the Overlook Hotel, where he, along with his wife Wendy and their son Danny, must live isolated from the rest of the world for the winter. But they aren''t prepared for the madness that lurks within.', 'https://image.tmdb.org/t/p/w500/uAR0AWqhQL1hQa69UDEbb2rE5Wx.jpg', 'https://image.tmdb.org/t/p/w1280/mmd1HnuvAzFc4iuVJcnBrhDNEKr.jpg', null, 'en', 'US', 694),
  ('b0b0acf9-7974-f868-11f1-048e125d672e', 'Star Wars', 'Star Wars', 1977, 121, 'Princess Leia is captured and held hostage by the evil Imperial forces in their effort to take over the galactic Empire. Venturesome Luke Skywalker and dashing captain Han Solo team together with the loveable robot duo R2-D2 and C-3PO to rescue the beautiful princess and restore peace and justice in the Empire.', 'https://image.tmdb.org/t/p/w500/6FfCtAuVAW8XJjZ7eWeLibRLWTw.jpg', 'https://image.tmdb.org/t/p/w1280/yUiXA68FfQeA8cRBhd0Ao0jIRZt.jpg', null, 'en', 'US', 11),
  ('4a5dd486-3d62-f7ff-b9a9-48c98fb58dde', 'The Empire Strikes Back', 'The Empire Strikes Back', 1980, 124, 'The epic saga continues as Luke Skywalker, in hopes of defeating the evil Galactic Empire, learns the ways of the Jedi from aging master Yoda. But Darth Vader is more determined than ever to capture Luke. Meanwhile, rebel leader Princess Leia, cocky Han Solo, Chewbacca, and droids C-3PO and R2-D2 are thrown into various stages of capture, betrayal and despair.', 'https://image.tmdb.org/t/p/w500/nNAeTmF4CtdSgMDplXTDPOpYzsX.jpg', 'https://image.tmdb.org/t/p/w1280/aJCtkxLLzkk1pECehVjKHA2lBgw.jpg', null, 'en', 'US', 1891),
  ('2327e6d5-752e-6f06-5ebe-e69c31c69b4c', 'Return of the Jedi', 'Return of the Jedi', 1983, 132, 'Luke Skywalker leads a mission to rescue his friend Han Solo from the clutches of Jabba the Hutt, the Emperor prepares to crush the Rebellion with a more powerful Death Star, and the Rebel fleet mounts a massive attack on the space station. Luke Skywalker confronts Darth Vader in a final climactic duel before the evil Emperor.', 'https://image.tmdb.org/t/p/w500/jQYlydvHm3kUix1f8prMucrplhm.jpg', 'https://image.tmdb.org/t/p/w1280/ziECpBRIyclmBNaFSWlvCfsKbMD.jpg', null, 'en', 'US', 1892),
  ('92c54f3b-20be-c13d-c145-16ce54856c87', 'Raiders of the Lost Ark', 'Raiders of the Lost Ark', 1981, 115, 'When Dr. Indiana Jones – the tweed-suited professor who just happens to be a celebrated archaeologist – is hired by the government to locate the legendary Ark of the Covenant, he finds himself up against the entire Nazi regime.', 'https://image.tmdb.org/t/p/w500/ceG9VzoRAVGwivFU403Wc3AHRys.jpg', 'https://image.tmdb.org/t/p/w1280/zPACwR32amTNvzId9qyapCWXYDJ.jpg', null, 'en', 'US', 85),
  ('b053ecd7-4d78-b459-34a6-fabe4af1bb44', 'Star Wars: Episode I - The Phantom Menace', 'Star Wars: Episode I - The Phantom Menace', 1999, 136, 'Anakin Skywalker, a young slave strong with the Force, is discovered on Tatooine. Meanwhile, the evil Sith have returned, enacting their plot for revenge against the Jedi.', 'https://image.tmdb.org/t/p/w500/6wkfovpn7Eq8dYNKaG5PY3q2oq6.jpg', 'https://image.tmdb.org/t/p/w1280/3TeGmKJfkik1D1rIoqGb1aR4k9c.jpg', null, 'en', 'US', 1893),
  ('4d8918f0-7a0e-390b-c055-4d05a810e743', 'Back to the Future', 'Back to the Future', 1985, 116, 'Eighties teenager Marty McFly is accidentally sent back in time to 1955, inadvertently disrupting his parents'' first meeting and attracting his mother''s romantic interest. Marty must repair the damage to history by rekindling his parents'' romance and - with the help of his eccentric inventor friend Doc Brown - return to 1985.', 'https://image.tmdb.org/t/p/w500/vN5B5WgYscRGcQpVhHl6p9DDTP0.jpg', 'https://image.tmdb.org/t/p/w1280/5bzPWQ2dFUl2aZKkp7ILJVVkRed.jpg', null, 'en', 'US', 105),
  ('e2abc7ba-2698-dca8-8069-894e5744551e', 'Saving Private Ryan', 'Saving Private Ryan', 1998, 169, 'As U.S. troops storm the beaches of Normandy, three brothers lie dead on the battlefield, with a fourth trapped behind enemy lines. Ranger captain John Miller and seven men are tasked with penetrating German-held territory and bringing the boy home.', 'https://image.tmdb.org/t/p/w500/uqx37cS8cpHg8U35f9U5IBlrCV3.jpg', 'https://image.tmdb.org/t/p/w1280/bdD39MpSVhKjxarTxLSfX6baoMP.jpg', null, 'en', 'US', 857),
  ('fdc5e573-4b57-01ef-66e6-a4355e6bd218', 'Dr. Strangelove or: How I Learned to Stop Worrying and Love the Bomb', 'Dr. Strangelove or: How I Learned to Stop Worrying and Love the Bomb', 1964, 95, 'After the insane General Jack D. Ripper initiates a nuclear strike on the Soviet Union, a war room full of politicians, generals and a Russian diplomat all frantically try to stop it.', 'https://image.tmdb.org/t/p/w500/6x7MzQ6BOMlRzam1StcmPO9v61g.jpg', 'https://image.tmdb.org/t/p/w1280/7i0L2ee4Iy0aXV6vR5u1ZmblOrx.jpg', null, 'en', 'GB', 935),
  ('1d5e021f-5e54-f18a-b9c6-3ec4966dbba6', 'Paths of Glory', 'Paths of Glory', 1957, 88, 'A commanding officer defends three scapegoats on trial for a failed offensive that occurred within the French Army in 1916.', 'https://image.tmdb.org/t/p/w500/tJXwtzOSNUC8dxJfrdvkNtGrrgW.jpg', 'https://image.tmdb.org/t/p/w1280/eTZkq5tI58Ec76AwPf1HOUoKtky.jpg', null, 'en', 'US', 975),
  ('6640305b-a3d9-0c4b-0bca-315ab6796bcf', 'Seven Samurai', '七人の侍', 1954, 207, 'A samurai answers a village''s request for protection after he falls on hard times. The town needs protection from bandits, so the samurai gathers six others to help him teach the people how to defend themselves, and the villagers provide the soldiers with food.', 'https://image.tmdb.org/t/p/w500/lOMGc8bnSwQhS4XyE1S99uH8NXf.jpg', 'https://image.tmdb.org/t/p/w1280/qvZ91FwMq6O47VViAr8vZNQz3WI.jpg', null, 'ja', 'JP', 346),
  ('b808ebc5-e54d-2fc7-aaf2-e149d33f5bc6', 'Rashomon', '羅生門', 1950, 88, 'Four people recount different versions of the story of a man''s murder and the rape of his wife.', 'https://image.tmdb.org/t/p/w500/vL7Xw04nFMHwnvXRFCmYYAzMUvY.jpg', 'https://image.tmdb.org/t/p/w1280/tDn1dA52bQH9B85vilHeU7C83W1.jpg', null, 'ja', 'JP', 548),
  ('857d924f-1179-13dd-40e6-63afbfd6cfd6', 'Ikiru', '生きる', 1952, 143, 'Kanji Watanabe is a middle-aged man who has worked in the same monotonous bureaucratic position for decades. Learning he has cancer, he starts to look for the meaning of his life.', 'https://image.tmdb.org/t/p/w500/dgNTS4EQDDVfkzJI5msKuHu2Ei3.jpg', 'https://image.tmdb.org/t/p/w1280/stiGp1XzkLSYdUUEWTyQOZRkr49.jpg', null, 'ja', 'JP', 3782),
  ('cb51ea58-7ecd-5dc9-a659-297cbb94bb5a', 'Tokyo Story', '東京物語', 1953, 137, 'The elderly Shukishi and his wife, Tomi, take the long journey from their small seaside village to visit their adult children in Tokyo. Their elder son, Koichi, a doctor, and their daughter, Shige, a hairdresser, don''t have much time to spend with their aged parents, and so it falls to Noriko, the widow of their younger son who was killed in the war, to keep her in-laws company.', 'https://image.tmdb.org/t/p/w500/g2YbTYKpY7N2yDSk7BfXZ18I5QV.jpg', 'https://image.tmdb.org/t/p/w1280/jLq0ol1f0ZKXni9R9GsPBcyPrNN.jpg', null, 'ja', 'JP', 18148),
  ('47d4b975-751e-c9c8-ad78-13d655661eae', 'Sunset Boulevard', 'Sunset Boulevard', 1950, 110, 'A hack screenwriter writes a screenplay for a former silent film star who has faded into Hollywood obscurity.', 'https://image.tmdb.org/t/p/w500/zt8aQ6ksqK6p1AopC5zVTDS9pKT.jpg', 'https://image.tmdb.org/t/p/w1280/p47ihFj4A7EpBjmPHdTj4ipyq1S.jpg', null, 'en', 'US', 599),
  ('fd38194e-c172-ef6a-da8c-d54390a56ceb', 'Singin'' in the Rain', 'Singin'' in the Rain', 1952, 103, 'In 1927 Hollywood, a silent film star falls for a chorus girl just as he and his paranoid screen partner struggle to make the difficult transition to talking pictures.', 'https://image.tmdb.org/t/p/w500/w03EiJVHP8Un77boQeE7hg9DVdU.jpg', 'https://image.tmdb.org/t/p/w1280/6qOyw4yfzbzTp5YsCX26C28Do0S.jpg', null, 'en', 'US', 872),
  ('d24b8b83-02c0-0e2c-d072-d57551047411', 'Metropolis', 'Metropolis', 1927, 148, 'In a futuristic city sharply divided between the rich and the poor, the son of the city''s mastermind meets a prophet who predicts the coming of a savior to mediate their differences.', 'https://image.tmdb.org/t/p/w500/kr9wXRN23zLuWJIelahas1mtnYj.jpg', 'https://image.tmdb.org/t/p/w1280/eeMoFKxjjiCi6iep2GEZtSAMYIr.jpg', null, 'de', 'DE', 19),
  ('54fb9a16-683b-bd85-3b12-07a9eca4d902', 'Things to Do in Denver When You''re Dead', 'Things to Do in Denver When You''re Dead', 1995, 116, 'Five different criminals face imminent death after botching a job quite badly.', 'https://image.tmdb.org/t/p/w500/3LxYzYybOVpnw0juCSlNL5cj8NK.jpg', 'https://image.tmdb.org/t/p/w1280/J4l8AvrK8ByAjnoKposMLh3ubL.jpg', null, 'en', 'FR', 400),
  ('90eb1413-8d1a-1e1f-18ac-299d5ffc1858', 'Breathless', 'À bout de souffle', 1960, 90, 'A small-time thief steals a car and impulsively murders a motorcycle policeman. Wanted by the authorities, he attempts to persuade a girl to run away to Italy with him.', 'https://image.tmdb.org/t/p/w500/9Wx0Wdn2EOqeCZU4SP6tlS3LOml.jpg', 'https://image.tmdb.org/t/p/w1280/4WGuyWf1f94CsEeVIIqDKGw5rmO.jpg', null, 'fr', 'FR', 269),
  ('aafd2ea6-a378-6e4d-5080-ea051656aad7', 'La Dolce Vita', 'La dolce vita', 1960, 176, 'Episodic journey of journalist Marcello who struggles to find his place in the world, torn between the allure of Rome''s elite social scene and the stifling domesticity offered by his girlfriend, all the while searching for a way to become a serious writer.', 'https://image.tmdb.org/t/p/w500/dZ2v0DAX4aCZartCzZdg4ZinSW2.jpg', 'https://image.tmdb.org/t/p/w1280/eN2NdMeJLNzLYzWIEEoaGzZAsiD.jpg', null, 'it', 'IT', 439),
  ('78a2356b-1215-4507-bcd6-56c4d3f3e8bd', 'Persona', 'Persona', 1966, 84, 'A young nurse, Alma, is put in charge of Elisabeth Vogler: an actress who is seemingly healthy in all respects, but will not talk. As they spend time together, Alma speaks to Elisabeth constantly, never receiving any answer.', 'https://image.tmdb.org/t/p/w500/yPTntWP9Wvew8vHN0jB7Z1EvEUN.jpg', 'https://image.tmdb.org/t/p/w1280/amr72SENYz7AM4Hq5WBXxFBJEY6.jpg', null, 'sv', 'SE', 797),
  ('5f5fa07d-5748-ddde-b163-9b558c2f542c', 'Bicycle Thieves', 'Ladri di biciclette', 1948, 89, 'Unemployed Antonio is elated when he finally finds work hanging posters around war-torn Rome. However on his first day, his bicycle—essential to his work—gets stolen. His job is doomed unless he can find the thief. With the help of his son, Antonio combs the city, becoming desperate for justice.', 'https://image.tmdb.org/t/p/w500/iPdVqIpmR3bRvOQJPrn4pr2KR3q.jpg', 'https://image.tmdb.org/t/p/w1280/nd6ItWuWGmTKhHXuxVC8kp86CmQ.jpg', null, 'it', 'IT', 5156),
  ('6e4b8301-d1d4-ff67-77a0-ede0933a62ee', 'Cinema Paradiso', 'Nuovo Cinema Paradiso', 1988, 124, 'A filmmaker recalls his childhood, when he fell in love with the movies at his village''s theater and formed a deep friendship with the theater''s projectionist.', 'https://image.tmdb.org/t/p/w500/gCI2AeMV4IHSewhJkzsur5MEp6R.jpg', 'https://image.tmdb.org/t/p/w1280/zoVeIgKzGJzpdG6Gwnr7iOYfIMU.jpg', null, 'it', 'IT', 11216),
  ('64a1840a-0afa-a66e-192c-f5bb5e24e8fa', 'Life Is Beautiful', 'La vita è bella', 1997, 116, 'A touching story of an Italian book seller of Jewish ancestry who lives in his own little fairy tale. His creative and happy life would come to an abrupt halt when his entire family is deported to a concentration camp during World War II. While locked up he tries to convince his son that the whole thing is just a game.', 'https://image.tmdb.org/t/p/w500/mfnkSeeVOBVheuyn2lo4tfmOPQb.jpg', 'https://image.tmdb.org/t/p/w1280/6aNKD81RHR1DqUUa8kOZ1TBY1Lp.jpg', null, 'it', 'IT', 637),
  ('063fe621-217d-31ee-9a01-6e8fc4d97170', 'Amélie', 'Le Fabuleux Destin d''Amélie Poulain', 2001, 122, 'At a tiny Parisian café, the adorable yet painfully shy Amélie accidentally discovers a gift for helping others. Soon Amelie is spending her days as a matchmaker, guardian angel, and all-around do-gooder. But when she bumps into a handsome stranger, will she find the courage to become the star of her very own love story?', 'https://image.tmdb.org/t/p/w500/nSxDa3M9aMvGVLoItzWTepQ5h5d.jpg', 'https://image.tmdb.org/t/p/w1280/6n53UI4mX9QMfe2S0Pgt8mGebY1.jpg', null, 'fr', 'FR', 194),
  ('e12307a2-78c1-a281-ce85-0135818e7d70', 'Spirited Away', '千と千尋の神隠し', 2001, 125, 'A young girl, Chihiro, becomes trapped in a strange new world of spirits. When her parents undergo a mysterious transformation, she must call upon the courage she never knew she had to free her family.', 'https://image.tmdb.org/t/p/w500/39wmItIWsg5sZMyRUHLkWBcuVCM.jpg', 'https://image.tmdb.org/t/p/w1280/dyJvKsNs2KP8qQnAXbRwDjblViy.jpg', null, 'ja', 'JP', 129),
  ('068ddc5d-ece5-4774-72bb-aaf62114992c', 'Princess Mononoke', 'もののけ姫', 1997, 134, 'Ashitaka, a prince of the disappearing Emishi people, is cursed by a demonized boar god and must journey to the west to find a cure. Along the way, he encounters San, a young human woman fighting to protect the forest, and Lady Eboshi, who is trying to destroy it. Ashitaka must find a way to bring balance to this conflict.', 'https://image.tmdb.org/t/p/w500/cMYCDADoLKLbB83g4WnJegaZimC.jpg', 'https://image.tmdb.org/t/p/w1280/gl0jzn4BupSbL2qMVeqrjKkF9Js.jpg', null, 'ja', 'JP', 128),
  ('454da97f-2135-1283-371a-14068ea68a36', 'Howl''s Moving Castle', 'ハウルの動く城', 2004, 119, 'Sophie, a young milliner, is turned into an elderly woman by a witch who enters her shop and curses her. She encounters a wizard named Howl and gets caught up in his resistance to fighting for the king.', 'https://image.tmdb.org/t/p/w500/13kOl2v0nD2OLbVSHnHk8GUFEhO.jpg', 'https://image.tmdb.org/t/p/w1280/nv5wwZou159v5OC61i4ElR7OqyY.jpg', null, 'ja', 'JP', 4935),
  ('dcd1a858-d2ab-8e3f-0806-8f00eee53574', 'Grave of the Fireflies', '火垂るの墓', 1988, 89, 'In the final months of World War II, 14-year-old Seita and his sister Setsuko are orphaned when their mother is killed during an air raid in Kobe, Japan. After a falling out with their aunt, they move into an abandoned bomb shelter. With no surviving relatives and their emergency rations depleted, Seita and Setsuko struggle to survive.', 'https://image.tmdb.org/t/p/w500/k9tv1rXZbOhH7eiCk378x61kNQ1.jpg', 'https://image.tmdb.org/t/p/w1280/aHaqZpOL7UyVu0nKqp3SMz0o2E1.jpg', null, 'ja', 'JP', 12477),
  ('d20b206c-699d-372e-ca92-39a9b1975dfe', 'The Departed', 'The Departed', 2006, 151, 'To take down South Boston''s Irish Mafia, the police send in one of their own to infiltrate the underworld, not realizing the syndicate has done likewise. While an undercover cop curries favor with the mob kingpin, a career criminal rises through the police ranks. But both sides soon discover there''s a mole among them.', 'https://image.tmdb.org/t/p/w500/nT97ifVT2J1yMQmeq20Qblg61T.jpg', 'https://image.tmdb.org/t/p/w1280/6WRrGYalXXveItfpnipYdayFkQB.jpg', null, 'en', 'US', 1422),
  ('3fefa124-f3b5-161d-a561-64f60830a7bd', 'Gladiator', 'Gladiator', 2000, 155, 'After the death of Emperor Marcus Aurelius, his devious son takes power and demotes Maximus, one of Rome''s most capable generals who Marcus preferred. Eventually, Maximus is forced to become a gladiator and battle to the death against other men for the amusement of paying audiences.', 'https://image.tmdb.org/t/p/w500/wN2xWp1eIwCKOD0BHTcErTBv1Uq.jpg', 'https://image.tmdb.org/t/p/w1280/Ar7QuJ7sJEiC0oP3I8fKBKIQD9u.jpg', null, 'en', 'US', 98),
  ('a4164453-3a67-0449-6d2a-1259aaed260a', 'Trainspotting', 'Trainspotting', 1996, 94, 'Heroin addict Mark Renton stumbles through bad ideas and sobriety attempts with his unreliable friends --Sick Boy, Begbie, Spud and Tommy. He also has an underage girlfriend, Diane, along for the ride. After cleaning up and moving from Edinburgh to London, Mark finds he can''t escape the life he left behind as Begbie and Sick Boy come knocking.', 'https://image.tmdb.org/t/p/w500/y0HmDV0bZDTtXWHqqYYbT9XoshB.jpg', 'https://image.tmdb.org/t/p/w1280/dkfBKDUIWP1peEszdqK10MkMZCP.jpg', null, 'en', 'GB', 627),
  ('56652aea-76b1-c067-079f-222dbe68e1eb', 'The Breakfast Club', 'The Breakfast Club', 1985, 98, 'Five high school students from different walks of life endure a Saturday detention under a power-hungry principal. The disparate group includes rebel John, princess Claire, outcast Allison, brainy Brian and Andrew, the jock. Each has a chance to tell his or her story, making the others see them a little differently -- and when the day ends, they question whether school will ever be the same.', 'https://image.tmdb.org/t/p/w500/gp4zlj7wgbiofLMNsTPndMuO3PN.jpg', 'https://image.tmdb.org/t/p/w1280/s5HDOmFZaPVQFjk9BxxDrLu1T0g.jpg', null, 'en', 'US', 2108),
  ('3b065136-329a-52aa-ca91-5600bd5556e9', 'The Treasure of the Sierra Madre', 'The Treasure of the Sierra Madre', 1948, 126, 'Two jobless Americans convince a prospector to travel to the mountains of Mexico with them in search of gold. But the hostile wilderness, local bandits, and greed all get in the way of their journey.', 'https://image.tmdb.org/t/p/w500/pWcst7zVbi8Z8W6GFrdNE7HHRxL.jpg', 'https://image.tmdb.org/t/p/w1280/osytHgkv86CTFKxo46l9P7ACEjm.jpg', null, 'en', 'US', 3090),
  ('263e3ad2-1c7c-cfd6-fad4-86607bd7d7ed', 'The Good, the Bad and the Ugly', 'Il buono, il brutto, il cattivo', 1966, 161, 'While the Civil War rages on between the Union and the Confederacy, three men – a quiet loner, a ruthless hitman, and a Mexican bandit – comb the American Southwest in search of a strongbox containing $200,000 in stolen gold.', 'https://image.tmdb.org/t/p/w500/bX2xnavhMYjWDoZp1VM6VnU1xwe.jpg', 'https://image.tmdb.org/t/p/w1280/Adrip2Jqzw56KeuV2nAxucKMNXA.jpg', null, 'it', 'IT', 429),
  ('8c75dcd1-1cdb-ada2-f163-b239e7855784', 'Once Upon a Time in the West', 'C''era una volta il West', 1968, 166, 'As the railroad builders advance unstoppably through the Arizona desert on their way to the sea, Jill arrives in the small town of Flagstone with the intention of starting a new life.', 'https://image.tmdb.org/t/p/w500/qbYgqOczabWNn2XKwgMtVrntD6P.jpg', 'https://image.tmdb.org/t/p/w1280/h31SOVlekuHXsMWVGxI8nPPfY82.jpg', null, 'it', 'IT', 335),
  ('f1d5f729-b024-d0ab-63f5-2002321cb48b', 'The Great Dictator', 'The Great Dictator', 1940, 125, 'Dictator Adenoid Hynkel tries to expand his empire while a poor Jewish barber tries to avoid persecution from Hynkel''s regime.', 'https://image.tmdb.org/t/p/w500/1QpO9wo7JWecZ4NiBuu625FiY1j.jpg', 'https://image.tmdb.org/t/p/w1280/c8Pi8F1FzpNebtgXcSjC9nWCdSW.jpg', null, 'en', 'US', 914),
  ('925b1158-b4ff-c151-079b-10de04c20126', 'Double Indemnity', 'Double Indemnity', 1944, 107, 'An insurance representative is seduced by a dissatisfied housewife into a scheme of insurance fraud and murder that arouses the suspicion of his colleague, a claims investigator.', 'https://image.tmdb.org/t/p/w500/rVNYZZgfhwqVMMWlBmxOfWqnwCj.jpg', 'https://image.tmdb.org/t/p/w1280/byQdu1nzQLI9t1VeoP1xuQfru3L.jpg', null, 'en', 'US', 996),
  ('12e15ea3-3356-2cac-5325-2d424563935b', 'A Streetcar Named Desire', 'A Streetcar Named Desire', 1951, 125, 'A disturbed, aging Southern belle moves in with her sister for solace — but being face-to-face with her brutish brother-in-law accelerates her downward spiral.', 'https://image.tmdb.org/t/p/w500/aicdlO5vt7z2ARm279eGzJeYCLQ.jpg', 'https://image.tmdb.org/t/p/w1280/or90vNrOVnYwi07fYYpQ3pbnjxP.jpg', null, 'en', 'US', 702),
  ('3940eff3-48dc-e548-4597-9ee762c1555b', 'The Elephant Man', 'The Elephant Man', 1980, 124, 'A Victorian surgeon rescues a heavily disfigured man being mistreated by his "owner" as a side-show freak. Behind his monstrous façade, there is revealed a person of great intelligence and sensitivity. Based on the true story of Joseph Merrick (called John Merrick in the film), a severely deformed man in 19th century London.', 'https://image.tmdb.org/t/p/w500/u0wpPYjuSt8DIe1Y3Vapnh8jcKE.jpg', 'https://image.tmdb.org/t/p/w1280/6huSptAsqYg3wbsi1jbMognSgmp.jpg', null, 'en', 'GB', 1955),
  ('c2f4e671-b81f-f498-3a4e-da1db174454f', 'City Lights', 'City Lights', 1931, 87, 'A tramp falls in love with a beautiful blind flower girl. His on-and-off friendship with a wealthy man allows him to be the girl''s benefactor and suitor.', 'https://image.tmdb.org/t/p/w500/bXNvzjULc9jrOVhGfjcc64uKZmZ.jpg', 'https://image.tmdb.org/t/p/w1280/qhKMAWxuu4TXCJCWVMqfveqanMP.jpg', null, 'en', 'US', 901),
  ('c7e76305-a28a-1867-c7b4-0b73fc955603', 'The General', 'The General', 1926, 79, 'During America’s Civil War, Union spies steal engineer Johnny Gray''s beloved locomotive, ''The General''—with Johnnie''s lady love aboard an attached boxcar—and he single-handedly must do all in his power to both get The General back and to rescue Annabelle.', 'https://image.tmdb.org/t/p/w500/nIp4gIXogCjfB1QABNsWwa9gSca.jpg', 'https://image.tmdb.org/t/p/w1280/mzox4HbcV9W42MH2dB1QsdDVGo3.jpg', null, 'en', 'US', 961),
  ('38994365-88bc-3eaf-7883-277215416ea5', 'Spider', 'Spider', 2002, 98, 'A mentally disturbed man takes residence in a halfway house. His mind gradually slips back into the realm created by his illness, where he replays a key part of his childhood.', 'https://image.tmdb.org/t/p/w500/zvm4WuYxTiGkRagRqHUey0meRQL.jpg', 'https://image.tmdb.org/t/p/w1280/zVVYFN9OjiSn43RVYrzgCOu7y6r.jpg', null, 'en', 'US', 9613),
  ('9aa847c0-ef15-84f5-671c-98c35be167b1', 'There Will Be Blood', 'There Will Be Blood', 2007, 158, 'Ruthless silver miner, turned oil prospector, Daniel Plainview, moves to oil-rich California. Using his son to project a trustworthy, family-man image, Plainview cons local landowners into selling him their valuable properties for a pittance. However, local preacher Eli Sunday suspects Plainview''s motives and intentions, starting a slow-burning feud that threatens both their lives.', 'https://image.tmdb.org/t/p/w500/fa0RDkAlCec0STeMNAhPaF89q6U.jpg', 'https://image.tmdb.org/t/p/w1280/9UAKA6ceZi6TgQwTAAMt7DWwYPI.jpg', null, 'en', 'US', 7345),
  ('e990fc32-b7fe-cc3c-27ac-7cec79865305', 'No Country for Old Men', 'No Country for Old Men', 2007, 122, 'Llewelyn Moss stumbles upon dead bodies, $2 million and a hoard of heroin in a Texas desert, but methodical killer Anton Chigurh comes looking for it, with local sheriff Ed Tom Bell hot on his trail. The roles of prey and predator blur as the violent pursuit of money and justice collide.', 'https://image.tmdb.org/t/p/w500/6d5XOczc226jECq0LIX0siKtgHR.jpg', 'https://image.tmdb.org/t/p/w1280/gddUsvfyySrM5k8B8wwJy2VRlBx.jpg', null, 'en', 'US', 6977)
